#!/bin/bash\n\n################################################################################\n# Script de Instalación del APK en Termux\n# Versión: 1.0.0\n# Descripción: Instala automáticamente el APK Admin en tu dispositivo Android\n# Plataforma: Termux (Android)\n################################################################################\n\n# Colores para la salida\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nBLUE='\\033[0;34m'\nMAGENTA='\\033[0;35m'\nCYAN='\\033[0;36m'\nNC='\\033[0m' # No Color\n\n# Emojis\nCHECK=\"✅\"\nERROR=\"❌\"\nWARN=\"⚠️ \"\nINFO=\"ℹ️ \"\nHOURGLASS=\"⏳\"\nGEAR=\"🔧\"\nBUILD=\"🔨\"\nFILE=\"📁\"\nSUCCESS=\"🎉\"\n\n# Directorios\nPROJECT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nAPK_DIR=\"$PROJECT_DIR/dist/apks\"\nLOG_FILE=\"$PROJECT_DIR/dist/install-apk-termux.log\"\n\n# Función para imprimir con color\nprint_header() {\n    echo -e \"${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}\"\n    echo -e \"${CYAN}$1${NC}\"\n    echo -e \"${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}\"\n}\n\nprint_success() {\n    echo -e \"${GREEN}${CHECK} $1${NC}\"\n}\n\nprint_error() {\n    echo -e \"${RED}${ERROR} $1${NC}\"\n}\n\nprint_warning() {\n    echo -e \"${YELLOW}${WARN}$1${NC}\"\n}\n\nprint_info() {\n    echo -e \"${BLUE}${INFO}$1${NC}\"\n}\n\nprint_step() {\n    echo -e \"${MAGENTA}$1${NC}\"\n}\n\n# Función para registrar en log\nlog_message() {\n    echo \"[$(date '+%Y-%m-%d %H:%M:%S')] $1\" >> \"$LOG_FILE\"\n}\n\n# Función para manejar errores\nerror_exit() {\n    print_error \"$1\"\n    log_message \"ERROR: $1\"\n    exit 1\n}\n\n# Banner inicial\nclear\necho -e \"${MAGENTA}\"\necho \"╔═══════════════════════════════════════════════════════════════╗\"\necho \"║                                                               ║\"\necho \"║    GESTOR DE CRÉDITOS Y COBRANZAS - INSTALACIÓN APK          ║\"\necho \"║                                                               ║\"\necho \"║              Script de Instalación en Termux                  ║\"\necho \"║                                                               ║\"\necho \"║                    Versión 1.0.0                              ║\"\necho \"║                                                               ║\"\necho \"╚═══════════════════════════════════════════════════════════════╝\"\necho -e \"${NC}\"\necho \"\"\n\n# Información inicial\nprint_info \"Directorio del proyecto: $PROJECT_DIR\"\nprint_info \"Directorio de APKs: $APK_DIR\"\necho \"\"\n\n# Inicializar log\necho \"═══════════════════════════════════════════════════════════════\" > \"$LOG_FILE\"\necho \"Instalación de APK - Gestor de Créditos\" >> \"$LOG_FILE\"\necho \"Fecha: $(date '+%Y-%m-%d %H:%M:%S')\" >> \"$LOG_FILE\"\necho \"Plataforma: Termux (Android)\" >> \"$LOG_FILE\"\necho \"═══════════════════════════════════════════════════════════════\" >> \"$LOG_FILE\"\necho \"\" >> \"$LOG_FILE\"\n\nlog_message \"Iniciando instalación de APK\"\n\n# PASO 1: Verificar Termux\nprint_header \"PASO 1: Verificando Termux\"\nif [ ! -d \"$PREFIX\" ]; then\n    error_exit \"Este script debe ejecutarse DENTRO de Termux\"\nfi\nprint_success \"Termux detectado correctamente\"\nlog_message \"Termux verificado\"\necho \"\"\n\n# PASO 2: Buscar APK\nprint_header \"PASO 2: Buscando APK\"\n\nif [ ! -d \"$APK_DIR\" ]; then\n    error_exit \"Directorio de APKs no encontrado: $APK_DIR\"\nfi\n\n# Buscar el APK más reciente\nAPK_FILE=$(find \"$APK_DIR\" -name \"gestor-creditos-admin-*.apk\" -type f | sort -r | head -1)\n\nif [ -z \"$APK_FILE\" ]; then\n    print_error \"No se encontró ningún APK en $APK_DIR\"\n    print_info \"APKs disponibles:\"\n    ls -lh \"$APK_DIR\" 2>/dev/null || print_warning \"Directorio vacío\"\n    echo \"\"\n    read -p \"¿Deseas compilar el APK ahora? (s/n): \" -n 1 -r\n    echo\n    if [[ $REPLY =~ ^[Ss]$ ]]; then\n        print_step \"Ejecutando compilación...\"\n        cd \"$PROJECT_DIR\"\n        bash compile-admin-termux.sh\n        # Buscar nuevamente después de compilar\n        APK_FILE=$(find \"$APK_DIR\" -name \"gestor-creditos-admin-*.apk\" -type f | sort -r | head -1)\n        if [ -z \"$APK_FILE\" ]; then\n            error_exit \"Compilación falló o APK no se encontró\"\n        fi\n    else\n        error_exit \"APK no encontrado y compilación cancelada\"\n    fi\nfi\n\nAPK_FILENAME=$(basename \"$APK_FILE\")\nAPK_SIZE=$(du -h \"$APK_FILE\" | cut -f1)\n\nprint_success \"APK encontrado: $APK_FILENAME\"\nprint_info \"Tamaño: $APK_SIZE\"\nprint_info \"Ubicación: $APK_FILE\"\nlog_message \"APK encontrado: $APK_FILE ($APK_SIZE)\"\necho \"\"\n\n# PASO 3: Verificar ADB\nprint_header \"PASO 3: Verificando ADB\"\n\nif ! command -v adb &> /dev/null; then\n    print_warning \"ADB no está instalado\"\n    print_step \"Instalando ADB...\"\n    pkg install -y android-tools >> \"$LOG_FILE\" 2>&1\n    if [ $? -ne 0 ]; then\n        error_exit \"Falló la instalación de ADB\"\n    fi\n    print_success \"ADB instalado\"\n    log_message \"ADB instalado correctamente\"\nelse\n    print_success \"ADB detectado: $(adb version | head -1)\"\n    log_message \"ADB encontrado: $(adb version | head -1)\"\nfi\necho \"\"\n\n# PASO 4: Verificar dispositivo\nprint_header \"PASO 4: Verificando Dispositivo\"\n\nprint_step \"Buscando dispositivos conectados...\"\necho \"\"\n\n# Esperar a que se conecte un dispositivo\nDEVICES=$(adb devices | grep -v \"^List\" | grep -v \"^$\" | wc -l)\n\nif [ \"$DEVICES\" -eq 0 ]; then\n    print_warning \"No se encontraron dispositivos conectados\"\n    print_info \"Por favor:\"\n    echo \"  1. Conecta tu dispositivo Android via USB\"\n    echo \"  2. Habilita USB Debugging en tu dispositivo\"\n    echo \"  3. Autoriza la conexión en tu dispositivo\"\n    echo \"\"\n    print_step \"Esperando dispositivo...\"\n    \n    # Esperar hasta 30 segundos\n    for i in {1..30}; do\n        DEVICES=$(adb devices | grep -v \"^List\" | grep -v \"^$\" | wc -l)\n        if [ \"$DEVICES\" -gt 0 ]; then\n            break\n        fi\n        echo -n \".\"\n        sleep 1\n    done\n    echo \"\"\n    \n    if [ \"$DEVICES\" -eq 0 ]; then\n        error_exit \"No se encontraron dispositivos después de 30 segundos\"\n    fi\nfi\n\nprint_success \"Dispositivo detectado\"\nprint_info \"Dispositivos conectados:\"\nadb devices | grep -v \"^List\" | grep -v \"^$\" | while read line; do\n    print_info \"  $line\"\ndone\nlog_message \"Dispositivo verificado\"\necho \"\"\n\n# PASO 5: Instalar APK\nprint_header \"PASO 5: Instalando APK\"\n\necho -e \"${MAGENTA}╔═══════════════════════════════════════════════════════════════╗${NC}\"\necho -e \"${MAGENTA}║                                                               ║${NC}\"\necho -e \"${MAGENTA}║         ${HOURGLASS} INSTALACIÓN EN PROGRESO ${HOURGLASS}                        ║${NC}\"\necho -e \"${MAGENTA}║                                                               ║${NC}\"\necho -e \"${MAGENTA}║     Esto puede tomar 1-2 minutos...                          ║${NC}\"\necho -e \"${MAGENTA}║                                                               ║${NC}\"\necho -e \"${MAGENTA}╚═══════════════════════════════════════════════════════════════╝${NC}\"\necho \"\"\n\nprint_step \"Ejecutando: adb install $APK_FILENAME\"\nlog_message \"Iniciando instalación de APK\"\n\nif adb install \"$APK_FILE\" >> \"$LOG_FILE\" 2>&1; then\n    print_success \"APK instalado correctamente\"\n    log_message \"APK instalado exitosamente\"\nelse\n    print_error \"Falló la instalación del APK\"\n    log_message \"ERROR: Falló la instalación del APK\"\n    print_info \"Logs: $LOG_FILE\"\n    exit 1\nfi\necho \"\"\n\n# PASO 6: Verificar instalación\nprint_header \"PASO 6: Verificando Instalación\"\n\nif adb shell pm list packages | grep -q \"com.gestorcreditos.admin\"; then\n    print_success \"Aplicación instalada correctamente\"\n    log_message \"Aplicación verificada en el dispositivo\"\nelse\n    print_warning \"No se pudo verificar la instalación\"\n    log_message \"ADVERTENCIA: No se pudo verificar la aplicación\"\nfi\necho \"\"\n\n# PASO 7: Resumen final\nprint_header \"RESUMEN FINAL\"\necho \"\"\necho -e \"${GREEN}╔═══════════════════════════════════════════════════════════════╗${NC}\"\necho -e \"${GREEN}║                                                               ║${NC}\"\necho -e \"${GREEN}║        ${SUCCESS} INSTALACIÓN COMPLETADA EXITOSAMENTE ${SUCCESS}                ║${NC}\"\necho -e \"${GREEN}║                                                               ║${NC}\"\necho -e \"${GREEN}╚═══════════════════════════════════════════════════════════════╝${NC}\"\necho \"\"\n\necho -e \"${CYAN}Información de la Instalación:${NC}\"\necho -e \"  Aplicación: Gestor de Créditos - Admin\"\necho -e \"  Versión: 1.0.0\"\necho -e \"  Package: com.gestorcreditos.admin\"\necho -e \"  Tamaño: $APK_SIZE\"\necho -e \"  Fecha: $(date '+%Y-%m-%d %H:%M:%S')\"\necho \"\"\n\necho -e \"${CYAN}Próximos Pasos:${NC}\"\necho -e \"  1. Abre la aplicación en tu dispositivo\"\necho -e \"  2. Toca 'Registrarse'\"\necho -e \"  3. Crea tu cuenta de administrador\"\necho -e \"  4. Inicia sesión\"\necho -e \"  5. ¡Comienza a usar!\"\necho \"\"\n\necho -e \"${CYAN}Para Lanzar la Aplicación:${NC}\"\necho -e \"  adb shell am start -n com.gestorcreditos.admin/.MainActivity\"\necho \"\"\n\necho -e \"${GREEN}${CHECK} ¡Todo completado! La aplicación está lista para usar.${NC}\"\necho \"\"\n\nlog_message \"Instalación finalizada exitosamente\"\nlog_message \"═══════════════════════════════════════════════════════════════\"\n\necho -e \"${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}\"\necho \"\"\n\n# Preguntar si desea lanzar la aplicación\nread -p \"¿Deseas lanzar la aplicación ahora? (s/n): \" -n 1 -r\necho\nif [[ $REPLY =~ ^[Ss]$ ]]; then\n    print_step \"Lanzando aplicación...\"\n    adb shell am start -n com.gestorcreditos.admin/.MainActivity\n    print_success \"Aplicación lanzada\"\n    log_message \"Aplicación lanzada desde Termux\"\nfi\n\necho \"\"\nprint_success \"¡Instalación completada!\"\necho \"\"\n
